from pybricks.tools import multitask, run_task, wait

from MBC_line16_Lib import line_bin_raw, line_error, line_init_port_multitask, line_ir_calibration, line_junction, line_junction_name, line_on_sensors, line_pos, line_read_all, line_width

async def subtask():
    while True:
        await wait(0)
        print(await line_ir_calibration())
        await wait(10)

async def main():
    await line_init_port_multitask(1, True)
    await multitask(
        subtask(),
    )


run_task(main())